svg.script:
(function () {
  var PHASES = [
    'Nitrogen gas (N₂) drifts in the atmosphere…',
    '⚡ Lightning strikes — 30,000°C, hotter than the Sun!',
    'The triple bond shatters! Nitrogen atoms fly free!',
    'Each nitrogen grabs an oxygen atom',
    'Rain carries them down to the soil…',
    '…soaking in as natural plant food!'
  ];

  function setPhase(txt) {
    var el = document.getElementById('nltg-phase');
    if (el) el.textContent = txt;
  }

  function animate() {
    /* Reset all elements to initial state */
    gsap.set('#nltg-n-left',  { x: 0, y: 0 });
    gsap.set('#nltg-n-right', { x: 0, y: 0 });
    gsap.set(['#nltg-bond1', '#nltg-bond2', '#nltg-bond3'], { opacity: 1 });
    gsap.set('#nltg-o-left',  { x: -80, opacity: 0, y: 0 });
    gsap.set('#nltg-o-right', { x:  80, opacity: 0, y: 0 });
    gsap.set(['#nltg-no-bond-left',  '#nltg-no-bond-right'],  { opacity: 0, y: 0 });
    gsap.set(['#nltg-no-text-left',  '#nltg-no-text-right'],  { opacity: 0, y: 0 });
    gsap.set('#nltg-lightning',      { opacity: 0 });
    gsap.set('#nltg-lightning-glow', { opacity: 0 });
    gsap.set('#nltg-flash',          { opacity: 0 });
    gsap.set('.nltg-rain',           { opacity: 0, y: 0 });
    gsap.set('#nltg-ground-glow',    { opacity: 0 });
    gsap.set('#nltg-plant',  { opacity: 0, scaleY: 0 });
    gsap.set('#nltg-label',  { opacity: 0 });
    gsap.set('#nltg-replay', { opacity: 0 });
    gsap.set('#nltg-phase',  { opacity: 0 });

    var tl = gsap.timeline();

    tl
      /* Phase 0 — N₂ drifts in the sky */
      .call(function () { setPhase(PHASES[0]); })
      .to('#nltg-phase', { opacity: 1, duration: 0.6 })

      /* Phase 1 — lightning strikes */
      .call(function () { setPhase(PHASES[1]); }, null, '+=0.9')
      .to('#nltg-lightning-glow', { opacity: 0.65, duration: 0.08 })
      .to('#nltg-lightning',      { opacity: 1,    duration: 0.08 }, '<')
      .to('#nltg-flash',          { opacity: 0.85, duration: 0.08 }, '<')
      .to('#nltg-lightning-glow', { opacity: 0, duration: 0.55 })
      .to('#nltg-lightning',      { opacity: 0, duration: 0.50 }, '<+=0.1')
      .to('#nltg-flash',          { opacity: 0, duration: 0.45 }, '<')

      /* Phase 2 — triple bond shatters, N atoms fly apart */
      .call(function () { setPhase(PHASES[2]); })
      .to('#nltg-n-left',  { x: -60, y: 47, duration: 0.65, ease: 'power2.out' })
      .to('#nltg-n-right', { x:  60, y: 47, duration: 0.65, ease: 'power2.out' }, '<')
      .to(['#nltg-bond1', '#nltg-bond2', '#nltg-bond3'],
          { opacity: 0, duration: 0.35 }, '<')

      /* Phase 3 — O atoms fly in, N-O bonds form */
      .call(function () { setPhase(PHASES[3]); }, null, '+=0.4')
      .to('#nltg-o-left',  { x: 0, opacity: 1, duration: 0.7, ease: 'power2.out' })
      .to('#nltg-o-right', { x: 0, opacity: 1, duration: 0.7, ease: 'power2.out' }, '<')
      .to(['#nltg-no-bond-left', '#nltg-no-bond-right'],
          { opacity: 1, duration: 0.4 }, '<+=0.5')
      .to(['#nltg-no-text-left', '#nltg-no-text-right'],
          { opacity: 1, duration: 0.4 })

      /* Phase 4 — NO molecules fall as rain */
      .call(function () { setPhase(PHASES[4]); }, null, '+=0.4')
      .to([
          '#nltg-n-left',       '#nltg-n-right',
          '#nltg-o-left',       '#nltg-o-right',
          '#nltg-no-bond-left', '#nltg-no-bond-right',
          '#nltg-no-text-left', '#nltg-no-text-right'
        ],
        { y: '+=86', duration: 1.5, ease: 'power1.in' })
      .to('.nltg-rain',
        { opacity: 0.8, y: 75, duration: 1.3, stagger: 0.08, ease: 'power1.in' }, '<')

      /* Phase 5 — ground absorption, plant emerges */
      .call(function () { setPhase(PHASES[5]); })
      .to('#nltg-ground-glow', { opacity: 0.7, duration: 0.3 })
      .to('#nltg-ground-glow', { opacity: 0,   duration: 1.0 })
      .to('#nltg-plant',
        { opacity: 1, scaleY: 1, duration: 0.85, ease: 'elastic.out(1, 0.5)' }, '<')

      /* End — formula label and replay button */
      .to('#nltg-label',  { opacity: 1, duration: 0.5 }, '+=0.2')
      .to('#nltg-replay', { opacity: 1, duration: 0.4 }, '+=0.2');
  }

  window.nltgReplay = function () {
    if (window.gsap) animate();
  };

  function setup() {
    var svgEl = document.getElementById('nltg-svg');
    if (!svgEl) return;
    var played = false;
    var io = new IntersectionObserver(function (entries) {
      if (entries[0].isIntersecting && !played) {
        played = true;
        io.disconnect();
        animate();
      }
    }, { threshold: 0.3 });
    io.observe(svgEl);
  }

  if (window.gsap) {
    setup();
  } else {
    var s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.5/gsap.min.js';
    s.onload = setup;
    document.head.appendChild(s);
  }
}());
